#include <bits/stdc++.h>
using namespace std;

// Function to check if it's possible to allocate books with given maximum pages
bool isPossible(vector<int>& books, int students, long long maxPages) {
    int currentStudent = 1;
    long long pagesForCurrentStudent = 0;

    for(int pages : books) {
        // If any single book has more pages than maxPages, it's impossible
        if(pages > maxPages) return false;

        // If adding this book exceeds maxPages, allocate to next student
        if(pagesForCurrentStudent + pages > maxPages) {
            currentStudent++;
            pagesForCurrentStudent = pages;

            // If we need more students than available, return false
            if(currentStudent > students) return false;
        } else {
            pagesForCurrentStudent += pages;
        }
    }

    return true;
}

// Function to find minimum of maximum pages
int findMinPages(vector<int>& books, int n, int students) {
    // If number of students is more than books, impossible to allocate
    if(students > n) return -1;

    long long left = 0, right = 0;

    // Find maximum pages in a book and sum of all pages
    for(int pages : books) {
        left = max(left, (long long)pages);
        right += pages;
    }

    // Binary search for minimum possible value
    while(left < right) {
        long long mid = left + (right - left) / 2;

        if(isPossible(books, students, mid)) {
            right = mid;
        } else {
            left = mid + 1;
        }
    }

    return left;
}

int main() {
    int t;
    cin >> t;  // Number of test cases

    while(t--) {
        int n, m;
        cin >> n >> m;  // n books, m students

        vector<int> books(n);
        for(int i = 0; i < n; i++) {
            cin >> books[i];  // Pages in each book
        }

        cout << findMinPages(books, n, m) << endl;
    }

    return 0;
}
